<section class="admin-page-head"><div><span class="eyebrow">Owner only</span><h1>Security center</h1><p>Account protection, production checks and security-sensitive history.</p></div><a class="button button-primary" href="<?= url('account/security') ?>"><i data-lucide="shield-check"></i>My security</a></section>

<section class="customer-stat-grid security-check-grid">
  <?php foreach($checks as $label=>$ok): ?><article><span><?= e($label) ?></span><strong><?= $ok?'Ready':'Action needed' ?></strong><i data-lucide="<?= $ok?'shield-check':'shield-alert' ?>"></i></article><?php endforeach; ?>
